		const tableExists = await trx.schema.hasTable(TABLE_NAME_JIRA_INSTALLATIONS);

		if (!tableExists) {
			await trx.schema.createTable(TABLE_NAME_JIRA_INSTALLATIONS, (table) => {
				table.uuid('_id').primary().notNullable();
				table.uuid('company_id').notNullable().references('_id').inTable('companies');
				table.string('cloud_id', 255).notNullable();
				table.string('site_url', 512).notNullable();
				table.text('access_token').notNullable();
				table.text('refresh_token').notNullable();
				table.timestamp('token_expires_at', { useTz: true }).notNullable();
				table
					.enum('status', ['active', 'uninstalled', 'needs_reauth'])
					.notNullable()
					.defaultTo('active');
				table
					.timestamp('created_at', { useTz: true })
					.defaultTo(trx.fn.now())
					.notNullable();
				table
					.timestamp('updated_at', { useTz: true })
					.defaultTo(trx.fn.now())
					.notNullable();

				table.index(['company_id']);
			});

			logger.log('Successfully created jira_installations table');
		} else {
			logger.log('jira_installations table already exists, skipping');
		}
	});
}

export async function down(knex: Knex): Promise<void> {
